WITH src AS (SELECT c.num_timed AS checkpoints_timed, c.num_requested AS checkpoints_requested, c.write_time AS checkpoint_write_time, c.sync_time AS checkpoint_sync_time, c.buffers_written AS buffers_checkpoint, w.buffers_clean, w.maxwritten_clean AS max_written_clean, NULL AS buffers_backend, NULL AS buffers_backend_fsync, w.buffers_alloc AS buffers_allocated, w.stats_reset FROM pg_stat_bgwriter AS w JOIN pg_stat_checkpointer AS c ON 1 = 1 /* These are both single-row views */) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.checkpoints_timed, src.checkpoints_requested, src.checkpoint_write_time, src.checkpoint_sync_time, src.buffers_checkpoint, src.buffers_clean, src.max_written_clean, src.buffers_backend, src.buffers_backend_fsync, src.buffers_allocated, src.stats_reset FROM src